{
    if (reg_class == ASMKIT_A64_TD_REGCLASS_SIMD) {
        return a64_td_simd_id(encoding, width);
    }
    if (reg_class == ASMKIT_A64_TD_REGCLASS_ZPR) {
        return encoding < 32u ? ASMKIT_AARCH64_REG_Z0 + encoding : 0u;
    }
    if (reg_class == ASMKIT_A64_TD_REGCLASS_PPR) {
        return encoding < 16u ? ASMKIT_AARCH64_REG_P0 + encoding : 0u;
    }
    if (reg_class == ASMKIT_A64_TD_REGCLASS_PNR) {
        return encoding < 16u ? ASMKIT_AARCH64_REG_PN0 + encoding : 0u;
    }
    if (reg_class == ASMKIT_A64_TD_REGCLASS_ZTR) {
        return encoding == 0u ? ASMKIT_AARCH64_REG_ZT0 : 0u;
    }
    if (reg_class == ASMKIT_A64_TD_REGCLASS_MATRIX_ARRAY) {
        return encoding == 0u ? ASMKIT_AARCH64_REG_ZA : 0u;
    }
    if (reg_class == ASMKIT_A64_TD_REGCLASS_MATRIX_TILE) {
        if (width == 8u) {
            return encoding == 0u ? ASMKIT_AARCH64_REG_ZAB0 : 0u;
        }
        if (width == 16u) {
            return encoding < 2u ? ASMKIT_AARCH64_REG_ZAH0 + encoding : 0u;
        }
        if (width == 32u) {
            return encoding < 4u ? ASMKIT_AARCH64_REG_ZAS0 + encoding : 0u;
        }
        if (width == 64u) {
            return encoding < 8u ? ASMKIT_AARCH64_REG_ZAD0 + encoding : 0u;
        }
        if (width == 128u) {
            return encoding < 16u ? ASMKIT_AARCH64_REG_ZAQ0 + encoding : 0u;
        }
        return 0u;
    }
    return a64_td_gpr_id(encoding, width, reg31_is_sp);
}

static int a64_td_reg_operand(uint32_t value, const asmkit_a64_td_operand_desc_t* desc, asmkit_operand_t* out_operand)
{
    uint32_t encoding;
    uint32_t reg_id;
    encoding = value & 0x1fu;
    if (desc->transform == ASMKIT_A64_TD_TRANSFORM_GPR_SEQ_PAIR) {
        if ((encoding & 1u) != 0u || encoding > 30u || (desc->width != 32u && desc->width != 64u)) {
            return 0;
        }
        reg_id = a64_td_gpr_id(encoding, desc->width, 0u);
        if (reg_id == ASMKIT_AARCH64_REG_INVALID) {
            return 0;
        }
        *out_operand = asmkit_operand_reg(reg_id, desc->width);
        out_operand->flags |= ASMKIT_OPERAND_FLAG_REGISTER_PAIR;
        return 1;
    }
    if (desc->transform == ASMKIT_A64_TD_TRANSFORM_SYSP_XZR_PAIR) {
        if (value != 0u || desc->width != 64u) {
            return 0;
        }
        *out_operand = asmkit_operand_reg(ASMKIT_AARCH64_REG_XZR, 64u);
        out_operand->flags |= ASMKIT_OPERAND_FLAG_REGISTER_PAIR;
        return 1;
    }
    if (desc->transform == ASMKIT_A64_TD_TRANSFORM_PNR_P8_TO_P15) {
        if (encoding > 7u) {
            return 0;
        }
        encoding += 8u;
    }
    if (desc->transform == ASMKIT_A64_TD_TRANSFORM_GPR_W12_TO_W15) {
        if (encoding > 3u || desc->width != 32u || desc->reg_class != ASMKIT_A64_TD_REGCLASS_GPR) {
            return 0;
        }
        encoding += 12u;
    }
    reg_id = a64_td_vector_id(encoding, desc->width, desc->reg31_is_sp, desc->reg_class);
    if (reg_id == ASMKIT_AARCH64_REG_INVALID) {
        return 0;
    }
    *out_operand = asmkit_operand_reg(reg_id, desc->width);
    if (desc->literal_value != 0u) {
        out_operand->flags |= ASMKIT_OPERAND_FLAG_VECTOR_LIST;
        out_operand->imm = desc->literal_value;
    }
    return 1;
}

static int a64_td_shifted_reg_operand(uint32_t value, const asmkit_a64_td_operand_desc_t* desc, asmkit_operand_t* out_operand)
{
    uint32_t amount;
    uint32_t shift_type;
    uint32_t max_amount;
    if (!a64_td_reg_operand(value, desc, out_operand)) {
        return 0;
    }
    amount = (value >> 5u) & 0x3fu;
    shift_type = (value >> 11u) & 3u;
    max_amount = desc->width == 32u ? 31u : 63u;
    if (amount > max_amount) {
        return 0;
    }
    if (desc->transform == ASMKIT_A64_TD_TRANSFORM_ARITH_SHIFTED_REG && shift_type == 3u) {
        return 0;
    }
    out_operand->shift_kind = (uint8_t)shift_type;
    out_operand->shift_amount = (uint8_t)amount;
    return 1;
}

static int a64_td_extended_reg_operand(uint32_t value, const asmkit_a64_td_operand_desc_t* desc, asmkit_operand_t* out_operand)
{
    uint32_t amount;
    uint32_t extend;
    uint32_t reg_id;
    uint16_t source_width;
    if (desc->reg_class != ASMKIT_A64_TD_REGCLASS_GPR) {
        return 0;
    }
    amount = (value >> 5u) & 7u;
    extend = (value >> 8u) & 7u;
    if (amount > 4u) {
        return 0;
    }
    source_width = desc->width == 32u ? 32u : ((extend == 3u || extend == 7u) ? 64u : 32u);
    if (desc->width != 32u && desc->width != 64u) {
        return 0;
    }
    reg_id = a64_td_gpr_id(value & 0x1fu, source_width, 0u);
    if (reg_id == ASMKIT_AARCH64_REG_INVALID) {
        return 0;
    }
    *out_operand = asmkit_operand_reg(reg_id, source_width);
    out_operand->flags |= ASMKIT_OPERAND_FLAG_AARCH64_EXTENDED_REG;
    out_operand->extend_kind = (uint8_t)extend;
    out_operand->extend_amount = (uint8_t)amount;
    return 1;
}

static int a64_td_decode_reg_operand(uint32_t value, const asmkit_a64_td_operand_desc_t* desc, asmkit_operand_t* out_operand)
{
    if (desc->transform == ASMKIT_A64_TD_TRANSFORM_ARITH_SHIFTED_REG || desc->transform == ASMKIT_A64_TD_TRANSFORM_LOGICAL_SHIFTED_REG) {
        return a64_td_shifted_reg_operand(value, desc, out_operand);
    }
    if (desc->transform == ASMKIT_A64_TD_TRANSFORM_ARITH_EXTENDED_REG) {
        return a64_td_extended_reg_operand(value, desc, out_operand);
    }
    return a64_td_reg_operand(value, desc, out_operand);
}

static int a64_td_imm_value(uint32_t value, const asmkit_a64_td_operand_desc_t* desc, int64_t* out_value)
{
    uint64_t logical_value;
    unsigned width;
    if (out_value == 0) {
        return 0;
    }
    switch (desc->transform) {
    case ASMKIT_A64_TD_TRANSFORM_RAW_SIGNED:
        width = a64_td_source_width(desc->source_mask);
        if (width == 0u) {
            *out_value = 0;
            return 1;
        }
        *out_value = a64_sign_extend(value, width);
        return 1;
    case ASMKIT_A64_TD_TRANSFORM_RAW_UNSIGNED_SCALED:
        *out_value = (int64_t)value * (int64_t)desc->literal_value;
        return desc->literal_value != 0u;
    case ASMKIT_A64_TD_TRANSFORM_RAW_UNSIGNED_OFFSET:
        *out_value = (int64_t)value + (int64_t)desc->literal_value;
        return desc->literal_value != 0u;
    case ASMKIT_A64_TD_TRANSFORM_FIXEDPOINT_SCALE:
        value |= 0x3fu & ~desc->source_mask;
        if (desc->literal_value == 0u || value >= desc->literal_value) {
            return 0;
        }
        *out_value = (int64_t)desc->literal_value - (int64_t)value;
        return 1;
    case ASMKIT_A64_TD_TRANSFORM_RAW_SIGNED_SCALED:
        width = a64_td_source_width(desc->source_mask);
        if (width == 0u || desc->literal_value == 0u) {
            return 0;
        }
        *out_value = a64_sign_extend(value, width) * (int64_t)desc->literal_value;
        return 1;
    case ASMKIT_A64_TD_TRANSFORM_VEC_SHIFT_RIGHT:
        if (desc->literal_value == 0u || value > desc->literal_value) {
            return 0;
        }
        *out_value = (int64_t)(desc->literal_value - value);
        return 1;
    case ASMKIT_A64_TD_TRANSFORM_VEC_SHIFT_RIGHT_NARROW:
        if (desc->literal_value == 0u) {
            return 0;
        }
        value |= desc->literal_value >> 1u;
        if (value > desc->literal_value) {
            return 0;
        }
        *out_value = (int64_t)(desc->literal_value - value);
        return 1;
    case ASMKIT_A64_TD_TRANSFORM_COMPLEX_ROTATE:
        *out_value = (int64_t)value * 90;
        return value <= 3u;
    case ASMKIT_A64_TD_TRANSFORM_ADD_SUB_SHIFTED_IMM:
        *out_value = (value & 0x1000u) != 0u ? (int64_t)((value & 0xfffu) << 12) : (int64_t)(value & 0xfffu);
        return 1;
    case ASMKIT_A64_TD_TRANSFORM_LOGICAL_IMM32:
    case ASMKIT_A64_TD_TRANSFORM_LOGICAL_IMM64:
        if (!a64_decode_logical_imm(value, desc->width, &logical_value)) {
            return 0;
        }
        *out_value = (int64_t)logical_value;
        return 1;
    case ASMKIT_A64_TD_TRANSFORM_MOV_SHIFT32:
    case ASMKIT_A64_TD_TRANSFORM_MOV_SHIFT64:
    case ASMKIT_A64_TD_TRANSFORM_RAW_UNSIGNED:
    default:
        *out_value = (int64_t)value;
        return 1;
    }
}

static asmkit_operand_t a64_td_pc_rel_operand(uint64_t address, uint32_t value, const asmkit_a64_td_operand_desc_t* desc)
{
    asmkit_operand_t operand;
    unsigned width;
    int64_t disp;
    uint64_t base;
    width = a64_td_source_width(desc->source_mask);
    if (width == 0u) {
        return asmkit_operand_none();
    }
    base = address;
    switch (desc->transform) {
    case ASMKIT_A64_TD_TRANSFORM_PC_REL_WORDS4:
        disp = a64_sign_extend(value, width) << 2;
        break;
    case ASMKIT_A64_TD_TRANSFORM_PC_REL_ADR:
        disp = a64_sign_extend(value, width);
        break;
    case ASMKIT_A64_TD_TRANSFORM_PC_REL_ADRP:
        disp = a64_sign_extend(value, width) << 12;
        base = address & ~(uint64_t)0xfffu;
        break;
    default:
        return asmkit_operand_none();
    }
    operand = asmkit_operand_pc_rel(disp, desc->width != 0u ? desc->width : (uint16_t)width);
    operand.abs_target = base + (uint64_t)disp;
    return operand;
}

static int a64_td_operand_values(const asmkit_a64_td_record_t* record, uint32_t word, uint32_t values[ASMKIT_MAX_OPERANDS])
{
    uint32_t i;
    if (record->operand_count > ASMKIT_MAX_OPERANDS) {
        return 0;
    }
    for (i = 0u; i < ASMKIT_MAX_OPERANDS; ++i) {
        values[i] = 0u;
    }
    for (i = 0u; i < record->piece_count; ++i) {
        const asmkit_a64_td_piece_t* piece = &asmkit_a64_td_pieces[record->piece_index + i];
        if (piece->operand_index >= ASMKIT_MAX_OPERANDS) {
            return 0;
        }
        values[piece->operand_index] |= ((word >> piece->dst_bit) & 1u) << piece->src_bit;
    }
    for (i = 0u; i < record->operand_count; ++i) {
        const asmkit_a64_td_operand_desc_t* desc = &asmkit_a64_td_operand_descs[record->operand_desc_index + i];
        if (desc->operand_index >= ASMKIT_MAX_OPERANDS) {
            return 0;
        }
        if (desc->kind == ASMKIT_A64_TD_OPERAND_OPAQUE && desc->source_mask == 0u && desc->width != 0u) {
            values[desc->operand_index] = desc->literal_value;
        }
        if (desc->kind == ASMKIT_A64_TD_OPERAND_IMM && desc->source_mask == 0u && desc->literal_value != 0u) {
            values[desc->operand_index] = desc->literal_value;
        }
    }
    return 1;
}

static int a64_td_record_operands_match(const asmkit_a64_td_record_t* record, uint32_t word)
{
    uint32_t values[ASMKIT_MAX_OPERANDS];
    uint32_t i;
    int64_t imm_value;
    if (!a64_td_operand_values(record, word, values)) {
        return 0;
    }
    for (i = 0u; i < record->operand_count; ++i) {
        const asmkit_a64_td_operand_desc_t* desc = &asmkit_a64_td_operand_descs[record->operand_desc_index + i];
        if (desc->operand_index >= ASMKIT_MAX_OPERANDS) {
            return 0;
        }
        if (desc->kind == ASMKIT_A64_TD_OPERAND_IMM && !a64_td_imm_value(values[desc->operand_index], desc, &imm_value)) {
            return 0;
        }
        if (desc->kind == ASMKIT_A64_TD_OPERAND_REG) {
            asmkit_operand_t operand;
            if (!a64_td_decode_reg_operand(values[desc->operand_index], desc, &operand)) {
                return 0;
            }
        }
    }
    return 1;
}

static int a64_decode_td_operands(const asmkit_a64_td_record_t* record, uint32_t word, uint64_t address, asmkit_inst_t* out_inst)
{
    uint32_t values[ASMKIT_MAX_OPERANDS];
    uint32_t i;
    if (record->operand_count == 0u || record->operand_count > ASMKIT_MAX_OPERANDS) {
        return record->operand_count == 0u;
    }
    if (!a64_td_operand_values(record, word, values)) {
        return 0;
    }
    for (i = 0u; i < record->operand_count; ++i) {
        const asmkit_a64_td_operand_desc_t* desc = &asmkit_a64_td_operand_descs[record->operand_desc_index + i];
        asmkit_operand_t operand = asmkit_operand_none();
        uint32_t value;
        int64_t imm_value;
        if (desc->operand_index >= ASMKIT_MAX_OPERANDS) {
            return 0;
        }
        value = values[desc->operand_index];
        if (desc->kind == ASMKIT_A64_TD_OPERAND_REG) {
            if (!a64_td_decode_reg_operand(value, desc, &operand)) {
                return 0;
            }
        } else if (desc->kind == ASMKIT_A64_TD_OPERAND_IMM) {
            if (!a64_td_imm_value(value, desc, &imm_value)) {
                return 0;
            }
            operand = asmkit_operand_imm(imm_value, desc->width);
        } else if (desc->kind == ASMKIT_A64_TD_OPERAND_OPAQUE) {
            operand = asmkit_operand_opaque((uint64_t)value, desc->width);
        } else if (desc->kind == ASMKIT_A64_TD_OPERAND_PC_REL) {
            operand = a64_td_pc_rel_operand(address, value, desc);
        } else {
            return 0;
        }
        operand.operand_index = desc->operand_index;
        out_inst->operands[desc->operand_index] = operand;
    }
    out_inst->operand_count = record->operand_count;
    return 1;
}

static asmkit_mnemonic_id_t a64_mnemonic_id(uint32_t id)
{
    switch (id) {
    case ASMKIT_A64_OTHER:
        return ASMKIT_GEN_AARCH64_MNEMONIC_OTHER_ID;
    case ASMKIT_A64_B:
        return ASMKIT_GEN_AARCH64_MNEMONIC_B_ID;
    case ASMKIT_A64_BL:
        return ASMKIT_GEN_AARCH64_MNEMONIC_BL_ID;
    case ASMKIT_A64_B_COND:
        return ASMKIT_GEN_AARCH64_MNEMONIC_B_ID;
    case ASMKIT_A64_CBZ:
        return ASMKIT_GEN_AARCH64_MNEMONIC_CBZ_ID;
    case ASMKIT_A64_CBNZ:
        return ASMKIT_GEN_AARCH64_MNEMONIC_CBNZ_ID;
    case ASMKIT_A64_TBZ:
        return ASMKIT_GEN_AARCH64_MNEMONIC_TBZ_ID;
    case ASMKIT_A64_TBNZ:
        return ASMKIT_GEN_AARCH64_MNEMONIC_TBNZ_ID;
    case ASMKIT_A64_ADR:
        return ASMKIT_GEN_AARCH64_MNEMONIC_ADR_ID;
    case ASMKIT_A64_ADRP:
        return ASMKIT_GEN_AARCH64_MNEMONIC_ADRP_ID;
    case ASMKIT_A64_LDR_LITERAL:
        return ASMKIT_GEN_AARCH64_MNEMONIC_LDR_ID;
    case ASMKIT_A64_PRFM_LITERAL:
        return ASMKIT_GEN_AARCH64_MNEMONIC_PRFM_ID;
    case ASMKIT_A64_BR:
        return ASMKIT_GEN_AARCH64_MNEMONIC_BR_ID;
    case ASMKIT_A64_BLR:
        return ASMKIT_GEN_AARCH64_MNEMONIC_BLR_ID;
    case ASMKIT_A64_RET:
        return ASMKIT_GEN_AARCH64_MNEMONIC_RET_ID;
    case ASMKIT_A64_BTI:
        return ASMKIT_GEN_AARCH64_MNEMONIC_BTI_ID;
    case ASMKIT_A64_PAC:
        return ASMKIT_GEN_AARCH64_MNEMONIC_PAC_ID;
    default:
        return ASMKIT_MNEMONIC_INVALID;
    }
}

static int a64_td_features_match(const asmkit_engine_t* engine, const asmkit_a64_td_record_t* record)
{
    uint32_t word;
    for (word = 0u; word < ASMKIT_FEATURE_WORD_COUNT; ++word) {
        uint64_t required = record->feature_bits[word];
        if ((required & ~asmkit_engine_feature_word(engine, word)) != 0u) {
            return 0;
        }
    }
    return 1;
}

static int a64_pstate_literal_features_match(const asmkit_engine_t* engine, const asmkit_a64_pstate_literal_t* literal)
{
    uint32_t word;
    for (word = 0u; word < ASMKIT_FEATURE_WORD_COUNT; ++word) {
        uint64_t required = literal->feature_bits[word];
        if ((required & ~asmkit_engine_feature_word(engine, word)) != 0u) {
            return 0;
        }
    }
    return 1;
}

static int a64_is_invalid_pstate(uint32_t op1, uint32_t op2)
{
    return op1 == 0u && (op2 == 0u || op2 == 1u || op2 == 2u);
}

static int a64_pstate_literal_match(const asmkit_engine_t* engine, uint8_t kind, uint32_t encoding)
{
    size_t i;
    for (i = 0u; i < ASMKIT_ARRAY_COUNT(asmkit_a64_pstate_literals); ++i) {
        const asmkit_a64_pstate_literal_t* literal = &asmkit_a64_pstate_literals[i];
        if (literal->kind == kind && literal->encoding == encoding && a64_pstate_literal_features_match(engine, literal)) {
            return 1;
        }
    }
    return 0;
}

static int a64_td_predicate_match(const asmkit_engine_t* engine, const asmkit_a64_td_record_t* record, uint32_t word)
{
    uint32_t op1;
    uint32_t op2;
    uint32_t crm_high;
    uint32_t pstate_field;
    if (record->predicate == ASMKIT_A64_TD_PREDICATE_NONE) {
        return 1;
    }
    op1 = (word >> 16) & 7u;
    op2 = (word >> 5) & 7u;
    if (a64_is_invalid_pstate(op1, op2)) {
        return 0;
    }
    if (record->predicate == ASMKIT_A64_TD_PREDICATE_PSTATE_IMM0_15) {
        pstate_field = (op1 << 3) | op2;
        return a64_pstate_literal_match(engine, ASMKIT_A64_PSTATE_KIND_IMM0_15, pstate_field);
    }
    if (record->predicate == ASMKIT_A64_TD_PREDICATE_PSTATE_IMM0_1) {
        crm_high = (word >> 9) & 7u;
        pstate_field = (crm_high << 6) | (op1 << 3) | op2;
        return a64_pstate_literal_match(engine, ASMKIT_A64_PSTATE_KIND_IMM0_1, pstate_field);
    }
    return 0;
}

static void a64_consider_td_record(
    const asmkit_engine_t* engine,
    uint32_t word,
    int check_features,
    const asmkit_a64_td_record_t* record,
    uint32_t record_index,
    const asmkit_a64_td_record_t** best_record,
    uint32_t* best_index,
    uint8_t* best_fixed_bits,
    int* have_match)
{
    if ((word & record->mask) != record->value) {
        return;
    }
    if (check_features && !a64_td_features_match(engine, record)) {
        return;
    }
    if (!a64_td_predicate_match(engine, record, word)) {
        return;
    }
    if (!a64_td_record_operands_match(record, word)) {
        return;
    }
    if (!*have_match || record->fixed_bits > *best_fixed_bits || (record->fixed_bits == *best_fixed_bits && record_index < *best_index)) {
        *best_record = record;
        *best_index = record_index;
        *best_fixed_bits = record->fixed_bits;
        *have_match = 1;
    }
}

static void a64_consider_td_indexed_bucket(
    const asmkit_engine_t* engine,
    uint32_t word,
    int check_features,
    const asmkit_a64_td_subbucket_desc_t* subdesc,
    const uint32_t* base_indices,
    uint32_t first,
    uint32_t count,
    const asmkit_a64_td_record_t** best_record,
    uint32_t* best_index,
    uint8_t* best_fixed_bits,
    int* have_match)
{
    const asmkit_a64_td_bucket_range_t* subbucket;
    uint32_t end;
    uint32_t i;
    if (subdesc->mask != 0u) {
        subbucket = a64_td_subbucket(word, subdesc);
        if (subbucket != 0) {
            end = subbucket->first + subbucket->count;
            for (i = subbucket->first; i < end; ++i) {
                uint32_t record_index = asmkit_a64_td_subbucket_indices[i];
                const asmkit_a64_td_record_t* record = &asmkit_a64_td_records[record_index];
                a64_consider_td_record(engine, word, check_features, record, record_index, best_record, best_index, best_fixed_bits, have_match);
            }
        }
        end = subdesc->fallback_first + subdesc->fallback_count;
        for (i = subdesc->fallback_first; i < end; ++i) {
            uint32_t record_index = asmkit_a64_td_subbucket_fallback_indices[i];
            const asmkit_a64_td_record_t* record = &asmkit_a64_td_records[record_index];
            a64_consider_td_record(engine, word, check_features, record, record_index, best_record, best_index, best_fixed_bits, have_match);
        }
        return;
    }
    end = first + count;
    for (i = first; i < end; ++i) {
        uint32_t record_index = base_indices[i];
        const asmkit_a64_td_record_t* record = &asmkit_a64_td_records[record_index];
        a64_consider_td_record(engine, word, check_features, record, record_index, best_record, best_index, best_fixed_bits, have_match);
    }
}

static const asmkit_a64_td_record_t* a64_find_td_record(const asmkit_engine_t* engine, uint32_t word, int check_features)
{
    const asmkit_a64_td_bucket_range_t* bucket;
    const asmkit_a64_td_record_t* best_record = 0;
    uint32_t best_index = (uint32_t)~0u;
    uint8_t best_fixed_bits = 0u;
    int have_match = 0;
    uint32_t bucket_index;
    bucket = a64_td_bucket(word);
    if (bucket != 0) {
        bucket_index = (uint32_t)(bucket - asmkit_a64_td_buckets);
        a64_consider_td_indexed_bucket(engine, word, check_features, &asmkit_a64_td_bucket_subdescs[bucket_index], asmkit_a64_td_bucket_indices, bucket->first, bucket->count, &best_record, &best_index, &best_fixed_bits, &have_match);
    }
    bucket = a64_td_fallback_bucket(word);
    if (bucket != 0) {
        bucket_index = (uint32_t)(bucket - asmkit_a64_td_fallback_buckets);
        a64_consider_td_indexed_bucket(engine, word, check_features, &asmkit_a64_td_fallback_bucket_subdescs[bucket_index], asmkit_a64_td_fallback_bucket_indices, bucket->first, bucket->count, &best_record, &best_index, &best_fixed_bits, &have_match);
    }
    a64_consider_td_indexed_bucket(engine, word, check_features, &asmkit_a64_td_bucket_fallback2_subdesc, asmkit_a64_td_bucket_fallback2_indices, 0u, ASMKIT_A64_TD_BUCKET_FALLBACK2_COUNT, &best_record, &best_index, &best_fixed_bits, &have_match);
    return best_record;
}

static asmkit_status_t a64_finish(
    const asmkit_engine_t* engine,
    const uint8_t* code,
    uint64_t address,
    asmkit_inst_t* out_inst,
    uint32_t id,
    asmkit_inst_class_t inst_class,
    uint32_t flags)
{
    asmkit_zero(out_inst, sizeof(*out_inst));
    out_inst->arch = ASMKIT_ARCH_AARCH64;
    out_inst->mode = engine->config.mode;
    out_inst->id = id;
    out_inst->mnemonic_id = a64_mnemonic_id(id);
    out_inst->inst_class = inst_class;
    out_inst->address = address;
    out_inst->size = 4u;
    out_inst->flags = flags;
    asmkit_copy(out_inst->bytes, code, 4u);
    return ASMKIT_OK;
}

static int a64_operand_is_gpr64_base(const asmkit_operand_t* operand)
{
    uint64_t reg;
    if (operand == 0 || operand->kind != ASMKIT_OP_REG || operand->width != 64u) {
        return 0;
    }
    reg = operand->reg;
    return (reg >= ASMKIT_AARCH64_REG_X0 && reg <= ASMKIT_AARCH64_REG_X28) || reg == ASMKIT_AARCH64_REG_FP || reg == ASMKIT_AARCH64_REG_LR || reg == ASMKIT_AARCH64_REG_SP;
}

static uint16_t a64_memory_access_width(uint32_t word, const asmkit_operand_t* data_operand)
{
    uint16_t width;
    width = (uint16_t)(8u << ((word >> 30u) & 3u));
    if (data_operand != 0 && data_operand->width > 64u) {
        return data_operand->width;
    }
    return width;
}

static void a64_remove_operands(asmkit_inst_t* inst, uint8_t first, uint8_t count)
{
    uint8_t old_count;
    uint8_t new_count;
    uint8_t i;
    if (first >= inst->operand_count || count == 0u) {
        return;
    }
    old_count = inst->operand_count;
    if ((uint8_t)(first + count) > old_count) {
        count = (uint8_t)(old_count - first);
    }
    new_count = (uint8_t)(old_count - count);
    for (i = first; (uint8_t)(i + count) < old_count; ++i) {
        inst->operands[i] = inst->operands[i + count];
        inst->operands[i].operand_index = i;
    }
    for (i = new_count; i < old_count; ++i) {
        inst->operands[i] = asmkit_operand_none();
        inst->operands[i].operand_index = i;
    }
    inst->operand_count = new_count;
}

static void a64_replace_base_disp_memory(asmkit_inst_t* inst, uint8_t base_index, uint8_t disp_index, uint32_t word, uint32_t flags)
{
    asmkit_operand_t mem;
    if (base_index >= inst->operand_count || disp_index >= inst->operand_count) {
        return;
    }
    if (!a64_operand_is_gpr64_base(&inst->operands[base_index]) || inst->operands[disp_index].kind != ASMKIT_OP_IMM) {
        return;
    }
    mem = asmkit_operand_mem_full(inst->operands[base_index].reg, ASMKIT_AARCH64_REG_INVALID, 1u, inst->operands[disp_index].imm, a64_memory_access_width(word, base_index != 0u ? &inst->operands[0] : 0), 64u);
    mem.flags = flags;
    mem.operand_index = base_index;
    inst->operands[base_index] = mem;
    a64_remove_operands(inst, disp_index, 1u);
}

static void a64_replace_base_index_memory(asmkit_inst_t* inst, uint8_t base_index, uint8_t index_index, uint8_t option_index, uint32_t word, uint32_t flags)
{
    asmkit_operand_t mem;
    uint8_t scale;
    if (base_index >= inst->operand_count || index_index >= inst->operand_count || option_index >= inst->operand_count) {
        return;
    }
    if (!a64_operand_is_gpr64_base(&inst->operands[base_index]) || inst->operands[index_index].kind != ASMKIT_OP_REG) {
        return;
    }
    if (inst->operands[option_index].kind != ASMKIT_OP_OPAQUE) {
        if (inst->operands[option_index].kind != ASMKIT_OP_IMM || inst->operands[option_index].width > 8u || inst->operands[option_index].imm < 0 || inst->operands[option_index].imm > 15) {
            return;
        }
    }
    scale = ((word >> 12u) & 1u) != 0u ? (uint8_t)(1u << ((word >> 30u) & 3u)) : 1u;
    mem = asmkit_operand_mem_full(inst->operands[base_index].reg, inst->operands[index_index].reg, scale, 0, a64_memory_access_width(word, base_index != 0u ? &inst->operands[0] : 0), 64u);
    mem.flags = flags;
    mem.operand_index = base_index;
    inst->operands[base_index] = mem;
    a64_remove_operands(inst, index_index, 2u);
}

static void a64_replace_base_index_fixed_scale_memory(asmkit_inst_t* inst, uint8_t base_index, uint8_t index_index, uint8_t scale, uint16_t width, uint32_t flags)
{
    asmkit_operand_t mem;
    if (base_index >= inst->operand_count || index_index >= inst->operand_count) {
        return;
    }
    if (!a64_operand_is_gpr64_base(&inst->operands[base_index]) || inst->operands[index_index].kind != ASMKIT_OP_REG) {
        return;
    }
    mem = asmkit_operand_mem_full(inst->operands[base_index].reg, inst->operands[index_index].reg, scale == 0u ? 1u : scale, 0, width, 64u);
    mem.flags = flags;
    mem.operand_index = base_index;
    inst->operands[base_index] = mem;
    a64_remove_operands(inst, index_index, 1u);
}

static void a64_replace_base_only_memory(asmkit_inst_t* inst, uint8_t base_index, uint32_t word, uint32_t flags)
{
    asmkit_operand_t mem;
    if (base_index >= inst->operand_count || !a64_operand_is_gpr64_base(&inst->operands[base_index])) {
        return;
    }
    mem = asmkit_operand_mem_full(inst->operands[base_index].reg, ASMKIT_AARCH64_REG_INVALID, 1u, 0, a64_memory_access_width(word, base_index != 0u ? &inst->operands[0] : 0), 64u);
    mem.flags = flags;
    mem.operand_index = base_index;
    inst->operands[base_index] = mem;
}

static int a64_record_has_writeback_base_first(uint32_t id)
{
    switch (id) {
    case ASMKIT_AARCH64_TDINST_LDRAAwriteback:
    case ASMKIT_AARCH64_TDINST_LDRABwriteback:
    case ASMKIT_AARCH64_TDINST_LDRBBpost:
    case ASMKIT_AARCH64_TDINST_LDRBBpre:
    case ASMKIT_AARCH64_TDINST_LDRBpost:
    case ASMKIT_AARCH64_TDINST_LDRBpre:
    case ASMKIT_AARCH64_TDINST_LDRDpost:
    case ASMKIT_AARCH64_TDINST_LDRDpre:
    case ASMKIT_AARCH64_TDINST_LDRHHpost:
    case ASMKIT_AARCH64_TDINST_LDRHHpre:
    case ASMKIT_AARCH64_TDINST_LDRHpost:
    case ASMKIT_AARCH64_TDINST_LDRHpre:
    case ASMKIT_AARCH64_TDINST_LDRQpost:
    case ASMKIT_AARCH64_TDINST_LDRQpre:
    case ASMKIT_AARCH64_TDINST_LDRSBWpost:
    case ASMKIT_AARCH64_TDINST_LDRSBWpre:
    case ASMKIT_AARCH64_TDINST_LDRSBXpost:
    case ASMKIT_AARCH64_TDINST_LDRSBXpre:
    case ASMKIT_AARCH64_TDINST_LDRSHWpost:
    case ASMKIT_AARCH64_TDINST_LDRSHWpre:
    case ASMKIT_AARCH64_TDINST_LDRSHXpost:
    case ASMKIT_AARCH64_TDINST_LDRSHXpre:
    case ASMKIT_AARCH64_TDINST_LDRSWpost:
    case ASMKIT_AARCH64_TDINST_LDRSWpre:
    case ASMKIT_AARCH64_TDINST_LDRSpost:
    case ASMKIT_AARCH64_TDINST_LDRSpre:
    case ASMKIT_AARCH64_TDINST_LDRWpost:
    case ASMKIT_AARCH64_TDINST_LDRWpre:
    case ASMKIT_AARCH64_TDINST_LDRXpost:
    case ASMKIT_AARCH64_TDINST_LDRXpre:
    case ASMKIT_AARCH64_TDINST_ST2GPostIndex:
    case ASMKIT_AARCH64_TDINST_ST2GPreIndex:
    case ASMKIT_AARCH64_TDINST_STGPostIndex:
    case ASMKIT_AARCH64_TDINST_STGPreIndex:
    case ASMKIT_AARCH64_TDINST_STRBBpost:
    case ASMKIT_AARCH64_TDINST_STRBBpre:
    case ASMKIT_AARCH64_TDINST_STRBpost:
    case ASMKIT_AARCH64_TDINST_STRBpre:
    case ASMKIT_AARCH64_TDINST_STRDpost:
    case ASMKIT_AARCH64_TDINST_STRDpre:
    case ASMKIT_AARCH64_TDINST_STRHHpost:
    case ASMKIT_AARCH64_TDINST_STRHHpre:
    case ASMKIT_AARCH64_TDINST_STRHpost:
    case ASMKIT_AARCH64_TDINST_STRHpre:
    case ASMKIT_AARCH64_TDINST_STRQpost:
    case ASMKIT_AARCH64_TDINST_STRQpre:
    case ASMKIT_AARCH64_TDINST_STRSpost:
    case ASMKIT_AARCH64_TDINST_STRSpre:
    case ASMKIT_AARCH64_TDINST_STRWpost:
    case ASMKIT_AARCH64_TDINST_STRWpre:
    case ASMKIT_AARCH64_TDINST_STRXpost:
    case ASMKIT_AARCH64_TDINST_STRXpre:
    case ASMKIT_AARCH64_TDINST_STZ2GPostIndex:
    case ASMKIT_AARCH64_TDINST_STZ2GPreIndex:
    case ASMKIT_AARCH64_TDINST_STZGPostIndex:
    case ASMKIT_AARCH64_TDINST_STZGPreIndex:
        return 1;
    default:
        return 0;
    }
}

static void a64_replace_writeback_base_disp_memory(asmkit_inst_t* inst, uint8_t base_index, uint8_t data_index, uint8_t disp_index, uint32_t word, uint32_t flags)
{
    asmkit_operand_t data;
    asmkit_operand_t mem;
    uint8_t i;
    if (base_index >= inst->operand_count || data_index >= inst->operand_count || disp_index >= inst->operand_count) {
        return;
    }
    if (!a64_operand_is_gpr64_base(&inst->operands[base_index]) || inst->operands[data_index].kind != ASMKIT_OP_REG || inst->operands[disp_index].kind != ASMKIT_OP_IMM) {
        return;
    }
    data = inst->operands[data_index];
    mem = asmkit_operand_mem_full(inst->operands[base_index].reg, ASMKIT_AARCH64_REG_INVALID, 1u, inst->operands[disp_index].imm, a64_memory_access_width(word, &data), 64u);
    mem.flags = flags;
    mem.operand_index = base_index;
    inst->operands[0] = data;
    inst->operands[1] = mem;
    for (i = 2u; i < inst->operand_count; ++i) {
        inst->operands[i] = asmkit_operand_none();
        inst->operands[i].operand_index = i;
    }
    inst->operand_count = 2u;
}

static int a64_record_is_prefetch_memory(const asmkit_a64_td_record_t* record)
{
    return record->mnemonic_id == ASMKIT_GEN_AARCH64_MNEMONIC_PRFM_ID || record->mnemonic_id == ASMKIT_GEN_AARCH64_MNEMONIC_PRFUM_ID;
}

static uint8_t a64_sve_gather_index_scale(const asmkit_a64_td_record_t* record)
{
    if (record->mnemonic_id == ASMKIT_GEN_AARCH64_MNEMONIC_LDFF1H_ID) {
        return 2u;
    }
    return 1u;
}

static void a64_fold_td_memory_operands(const asmkit_a64_td_record_t* record, uint32_t word, asmkit_inst_t* inst)
{
    uint32_t load_flags = ASMKIT_OPERAND_FLAG_EXPLICIT | ASMKIT_OPERAND_FLAG_MEMORY | ASMKIT_OPERAND_FLAG_READ;
    uint32_t store_flags = ASMKIT_OPERAND_FLAG_EXPLICIT | ASMKIT_OPERAND_FLAG_MEMORY | ASMKIT_OPERAND_FLAG_WRITE;
    uint32_t writeback_flags = ASMKIT_OPERAND_FLAG_EXPLICIT | ASMKIT_OPERAND_FLAG_MEMORY | ASMKIT_OPERAND_FLAG_READ | ASMKIT_OPERAND_FLAG_WRITE;
    if (record->inst_class != ASMKIT_INST_LOAD && record->inst_class != ASMKIT_INST_STORE && !a64_record_is_prefetch_memory(record)) {
        return;
    }
    if ((word & UINT32_C(0x3a000000)) == UINT32_C(0x28000000)) {
        return;
    }
    if (a64_record_has_writeback_base_first(record->id) && inst->operand_count == 3u) {
        a64_replace_writeback_base_disp_memory(inst, 0u, 1u, 2u, word, writeback_flags);
        return;
    }
    if (inst->operand_count == 4u && inst->operands[0].kind == ASMKIT_OP_REG && inst->operands[1].kind == ASMKIT_OP_REG && inst->operands[2].kind == ASMKIT_OP_REG && a64_operand_is_gpr64_base(&inst->operands[3])) {
        a64_replace_base_only_memory(inst, 3u, word, record->inst_class == ASMKIT_INST_LOAD ? load_flags : store_flags);
        return;
    }
    if (inst->operand_count == 4u && inst->operands[0].kind == ASMKIT_OP_REG && a64_operand_is_gpr64_base(&inst->operands[1]) && inst->operands[2].kind == ASMKIT_OP_REG) {
        a64_replace_base_index_memory(inst, 1u, 2u, 3u, word, record->inst_class == ASMKIT_INST_LOAD ? load_flags : store_flags);
        return;
    }
    if (inst->operand_count == 4u && inst->operands[0].kind == ASMKIT_OP_REG && inst->operands[1].kind == ASMKIT_OP_REG && a64_operand_is_gpr64_base(&inst->operands[2]) && inst->operands[3].kind == ASMKIT_OP_REG) {
        uint8_t scale = a64_sve_gather_index_scale(record);
        a64_replace_base_index_fixed_scale_memory(inst, 2u, 3u, scale, (uint16_t)(scale * 8u), load_flags);
        return;
    }
    if (a64_record_is_prefetch_memory(record) && inst->operand_count == 3u && inst->operands[0].kind == ASMKIT_OP_OPAQUE && a64_operand_is_gpr64_base(&inst->operands[1]) && inst->operands[2].kind == ASMKIT_OP_IMM) {
        a64_replace_base_disp_memory(inst, 1u, 2u, word, load_flags);
        return;
    }
    if (inst->operand_count == 3u && inst->operands[0].kind == ASMKIT_OP_REG && a64_operand_is_gpr64_base(&inst->operands[1]) && inst->operands[2].kind == ASMKIT_OP_IMM) {
        a64_replace_base_disp_memory(inst, 1u, 2u, word, record->inst_class == ASMKIT_INST_LOAD ? load_flags : store_flags);
        return;
    }
    if (inst->operand_count == 3u && inst->operands[0].kind == ASMKIT_OP_REG && inst->operands[1].kind == ASMKIT_OP_REG && a64_operand_is_gpr64_base(&inst->operands[2])) {
        a64_replace_base_only_memory(inst, 2u, word, ASMKIT_OPERAND_FLAG_EXPLICIT | ASMKIT_OPERAND_FLAG_MEMORY | ASMKIT_OPERAND_FLAG_READ | ASMKIT_OPERAND_FLAG_WRITE);
        return;
    }
    if (inst->operand_count == 2u && inst->operands[0].kind == ASMKIT_OP_REG && a64_operand_is_gpr64_base(&inst->operands[1])) {
        a64_replace_base_only_memory(inst, 1u, word, record->inst_class == ASMKIT_INST_LOAD ? load_flags : store_flags);
    }
}

static asmkit_status_t a64_finish_td(
    const asmkit_engine_t* engine,
    const uint8_t* code,
    uint64_t address,
    asmkit_inst_t* out_inst,
    const asmkit_a64_td_record_t* record)
{
    uint32_t word;
    asmkit_zero(out_inst, sizeof(*out_inst));
    out_inst->arch = ASMKIT_ARCH_AARCH64;
    out_inst->mode = engine->config.mode;
    out_inst->id = record->id;
    out_inst->mnemonic_id = record->mnemonic_id;
    out_inst->inst_class = record->inst_class;
    out_inst->address = address;
    out_inst->size = 4u;
    out_inst->flags = record->flags;
    asmkit_copy(out_inst->bytes, code, 4u);
    word = asmkit_load32le(code);
    if (!a64_decode_td_operands(record, word, address, out_inst)) {
        return ASMKIT_ERR_DECODE_FAILED;
    }
    a64_fold_td_memory_operands(record, word, out_inst);
    return ASMKIT_OK;
}

static void a64_set_reg_operand(asmkit_inst_t* inst, uint8_t index, uint32_t reg, uint16_t width)
{
    if (index >= ASMKIT_MAX_OPERANDS) {
        return;
    }
    inst->operands[index] = asmkit_operand_reg(reg, width);
    inst->operands[index].operand_index = index;
    inst->operands[index].flags |= ASMKIT_OPERAND_FLAG_EXPLICIT | ASMKIT_OPERAND_FLAG_READ;
    if (inst->operand_count <= index) {
        inst->operand_count = (uint8_t)(index + 1u);
    }
}

static void a64_set_imm_operand(asmkit_inst_t* inst, uint8_t index, int64_t imm, uint16_t width)
{
    if (index >= ASMKIT_MAX_OPERANDS) {
        return;
    }
    inst->operands[index] = asmkit_operand_imm(imm, width);
    inst->operands[index].operand_index = index;
    inst->operands[index].flags |= ASMKIT_OPERAND_FLAG_EXPLICIT | ASMKIT_OPERAND_FLAG_READ;
    if (inst->operand_count <= index) {
        inst->operand_count = (uint8_t)(index + 1u);
    }
}

static void a64_set_opaque_operand(asmkit_inst_t* inst, uint8_t index, uint64_t value, uint16_t width)
{
    if (index >= ASMKIT_MAX_OPERANDS) {
        return;
    }
    inst->operands[index] = asmkit_operand_opaque(value, width);
    inst->operands[index].operand_index = index;
    if (inst->operand_count <= index) {
        inst->operand_count = (uint8_t)(index + 1u);
    }
}

static void a64_set_pc_operand(asmkit_inst_t* inst, uint8_t index, int64_t disp, uint64_t target, uint8_t width)
{
    if (index >= ASMKIT_MAX_OPERANDS) {
        return;
    }
    inst->operands[index] = asmkit_operand_pc_rel(disp, width);
    inst->operands[index].abs_target = target;
    inst->operands[index].operand_index = index;
    inst->operands[index].flags |= ASMKIT_OPERAND_FLAG_EXPLICIT | ASMKIT_OPERAND_FLAG_READ | ASMKIT_OPERAND_FLAG_RELATIVE | ASMKIT_OPERAND_FLAG_SIGNED;
    if (inst->operand_count <= index) {
        inst->operand_count = (uint8_t)(index + 1u);
    }
}

static void a64_set_literal_rt_operand(asmkit_inst_t* inst, uint32_t word)
{
    uint32_t rt;
    uint32_t opc;
    rt = word & 0x1fu;
    opc = (word >> 30) & 3u;
    if ((word & 0x04000000u) != 0u) {
        uint16_t width = opc == 0u ? 32u : (opc == 1u ? 64u : 128u);
        a64_set_reg_operand(inst, 0u, a64_td_simd_id(rt, width), width);
    } else {
        uint16_t width = opc == 0u ? 32u : 64u;
        a64_set_reg_operand(inst, 0u, a64_td_gpr_id(rt, width, 0u), width);
    }
}

asmkit_status_t asmkit_gen_aarch64_decode_one(
    const asmkit_engine_t* engine,
    const uint8_t* code,
    size_t code_size,
    uint64_t address,
    asmkit_inst_t* out_inst)
{
    const asmkit_a64_td_record_t* td_record;
    uint32_t w;
    int64_t disp;
    uint32_t imm;
    uint64_t page;

    if (engine == 0 || code == 0 || out_inst == 0) {
        return ASMKIT_ERR_INVALID_ARGUMENT;
    }
    if (engine->config.mode != ASMKIT_MODE_AARCH64 || code_size < 4u) {
        return ASMKIT_ERR_DECODE_FAILED;
    }
    w = asmkit_load32le(code);

    if (w == 0xd503241fu || w == 0xd503245fu || w == 0xd503249fu || w == 0xd50324dfu) {
        if (!asmkit_target_feature_enabled(engine, ASMKIT_AARCH64_FEATURE_BRANCHTARGETID)) {
            return ASMKIT_ERR_UNSUPPORTED_FEATURE;
        }
        (void)a64_finish(engine, code, address, out_inst, ASMKIT_A64_BTI, ASMKIT_INST_BTI, 0u);
        a64_set_imm_operand(out_inst, 0u, (w >> 5u) & 0x7fu, 7u);
        return ASMKIT_OK;
    }

    td_record = a64_find_td_record(engine, w, 1);
    if (td_record != 0) {
        return a64_finish_td(engine, code, address, out_inst, td_record);
    }
    if (a64_find_td_record(engine, w, 0) != 0) {
        return ASMKIT_ERR_UNSUPPORTED_FEATURE;
    }

    if ((w & 0xfc000000u) == 0x14000000u) {
        disp = a64_sign_extend(w & 0x03ffffffu, 26u) << 2;
        (void)a64_finish(engine, code, address, out_inst, ASMKIT_A64_B, ASMKIT_INST_DIRECT_BRANCH,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_DIRECT | ASMKIT_INST_FLAG_TERMINATOR);
        a64_set_pc_operand(out_inst, 0u, disp, address + (uint64_t)disp, 26u);
        return ASMKIT_OK;
    }
    if ((w & 0xfc000000u) == 0x94000000u) {
        disp = a64_sign_extend(w & 0x03ffffffu, 26u) << 2;
        (void)a64_finish(engine, code, address, out_inst, ASMKIT_A64_BL, ASMKIT_INST_DIRECT_CALL,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_DIRECT | ASMKIT_INST_FLAG_CALL);
        a64_set_pc_operand(out_inst, 0u, disp, address + (uint64_t)disp, 26u);
        return ASMKIT_OK;
    }
    if ((w & 0xff000010u) == 0x54000000u) {
        disp = a64_sign_extend((w >> 5) & 0x7ffffu, 19u) << 2;
        (void)a64_finish(engine, code, address, out_inst, ASMKIT_A64_B_COND, ASMKIT_INST_COND_BRANCH,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_DIRECT | ASMKIT_INST_FLAG_CONDITIONAL);
        a64_set_imm_operand(out_inst, 0u, w & 0x0fu, 4u);
        a64_set_pc_operand(out_inst, 1u, disp, address + (uint64_t)disp, 19u);
        return ASMKIT_OK;
    }
    if ((w & 0x7e000000u) == 0x34000000u) {
        disp = a64_sign_extend((w >> 5) & 0x7ffffu, 19u) << 2;
        (void)a64_finish(engine, code, address, out_inst,
            ((w & 0x01000000u) != 0u) ? ASMKIT_A64_CBNZ : ASMKIT_A64_CBZ,
            ASMKIT_INST_COND_BRANCH,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_DIRECT | ASMKIT_INST_FLAG_CONDITIONAL);
        a64_set_reg_operand(out_inst, 0u, a64_td_gpr_id(w & 0x1fu, (w & 0x80000000u) != 0u ? 64u : 32u, 0u), (w & 0x80000000u) != 0u ? 64u : 32u);
        a64_set_pc_operand(out_inst, 1u, disp, address + (uint64_t)disp, 19u);
        return ASMKIT_OK;
    }
    if ((w & 0x7e000000u) == 0x36000000u) {
        disp = a64_sign_extend((w >> 5) & 0x3fffu, 14u) << 2;
        (void)a64_finish(engine, code, address, out_inst,
            ((w & 0x01000000u) != 0u) ? ASMKIT_A64_TBNZ : ASMKIT_A64_TBZ,
            ASMKIT_INST_COND_BRANCH,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_DIRECT | ASMKIT_INST_FLAG_CONDITIONAL);
        imm = ((w >> 19) & 0x1fu) | ((w >> 26) & 0x20u);
        a64_set_reg_operand(out_inst, 0u, a64_td_gpr_id(w & 0x1fu, imm >= 32u ? 64u : 32u, 0u), imm >= 32u ? 64u : 32u);
        a64_set_imm_operand(out_inst, 1u, imm, 6u);
        a64_set_pc_operand(out_inst, 2u, disp, address + (uint64_t)disp, 14u);
        return ASMKIT_OK;
    }
    if ((w & 0x9f000000u) == 0x10000000u || (w & 0x9f000000u) == 0x90000000u) {
        imm = ((w >> 29) & 0x3u) | (((w >> 5) & 0x7ffffu) << 2);
        disp = a64_sign_extend(imm, 21u);
        if ((w & 0x9f000000u) == 0x90000000u) {
            page = address & ~(uint64_t)0xfffu;
            (void)a64_finish(engine, code, address, out_inst, ASMKIT_A64_ADRP, ASMKIT_INST_ALU, ASMKIT_INST_FLAG_PC_RELATIVE);
            a64_set_reg_operand(out_inst, 0u, a64_td_gpr_id(w & 0x1fu, 64u, 0u), 64u);
            a64_set_pc_operand(out_inst, 1u, disp << 12, page + (uint64_t)(disp << 12), 21u);
        } else {
            (void)a64_finish(engine, code, address, out_inst, ASMKIT_A64_ADR, ASMKIT_INST_ALU, ASMKIT_INST_FLAG_PC_RELATIVE);
            a64_set_reg_operand(out_inst, 0u, a64_td_gpr_id(w & 0x1fu, 64u, 0u), 64u);
            a64_set_pc_operand(out_inst, 1u, disp, address + (uint64_t)disp, 21u);
        }
        return ASMKIT_OK;
    }
    if ((w & 0x3b000000u) == 0x18000000u) {
        disp = a64_sign_extend((w >> 5) & 0x7ffffu, 19u) << 2;
        (void)a64_finish(engine, code, address, out_inst, ASMKIT_A64_LDR_LITERAL, ASMKIT_INST_LOAD,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_LITERAL);
        a64_set_literal_rt_operand(out_inst, w);
        a64_set_pc_operand(out_inst, 1u, disp, address + (uint64_t)disp, 19u);
        return ASMKIT_OK;
    }
    if ((w & 0xff000000u) == 0xd8000000u) {
        disp = a64_sign_extend((w >> 5) & 0x7ffffu, 19u) << 2;
        (void)a64_finish(engine, code, address, out_inst, ASMKIT_A64_PRFM_LITERAL, ASMKIT_INST_HINT,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_LITERAL);
        a64_set_opaque_operand(out_inst, 0u, w & 0x1fu, 5u);
        a64_set_pc_operand(out_inst, 1u, disp, address + (uint64_t)disp, 19u);
        return ASMKIT_OK;
    }
    if ((w & 0xfffffc1fu) == 0xd61f0000u) {
        return a64_finish(engine, code, address, out_inst, ASMKIT_A64_BR, ASMKIT_INST_INDIRECT_BRANCH, ASMKIT_INST_FLAG_TERMINATOR);
    }
    if ((w & 0xfffffc1fu) == 0xd63f0000u) {
        return a64_finish(engine, code, address, out_inst, ASMKIT_A64_BLR, ASMKIT_INST_INDIRECT_CALL, ASMKIT_INST_FLAG_CALL);
    }
    if ((w & 0xfffffc1fu) == 0xd65f0000u) {
        return a64_finish(engine, code, address, out_inst, ASMKIT_A64_RET, ASMKIT_INST_RETURN, ASMKIT_INST_FLAG_RETURN | ASMKIT_INST_FLAG_TERMINATOR);
    }
    if ((w & 0xfffff000u) == 0xd5032000u) {
        return a64_finish(engine, code, address, out_inst, ASMKIT_A64_PAC, ASMKIT_INST_PAC, 0u);
    }
    return a64_finish(engine, code, address, out_inst, ASMKIT_A64_OTHER, ASMKIT_INST_OTHER, 0u);
}
